import EditFieldForm from "./edit-field-form"

// SERVER COMPONENT
export default async function EditFieldPage({
  params,
}: {
  params: { id: string }
}) {
  const { id } = params

  let existingData = null

  try {
    const res = await fetch(`${process.env.NEXT_PUBLIC_API_URL}/owner/fields/${id}`, {
      method: "GET",
      cache: "no-store",
      credentials: "include",
    })

    if (!res.ok) {
      console.error("API GET FIELD FAILED:", await res.text())
      throw new Error("Không thể tải dữ liệu sân.")
    }

    existingData = await res.json()

  } catch (error) {
    console.error("FETCH FIELD ERROR:", error)

    // fallback để tránh crash UI
    existingData = {
      name: "",
      type: "soccer",
      location: "",
      address: "",
      capacity: "0",
      price: "0",
      description: "",
      status: "active",
      amenities: [],
      openTime: "06:00",
      closeTime: "22:00",
    }
  }

  return <EditFieldForm fieldId={id} existingData={existingData} />
}
